		des := dess[jj]
		id := total_ship + jj

		maxSlots := dispatch.AssignsLen
		if maxSlots == 0 || (maxSlots < MAXASSIGNS && dispatch.Assigns[maxSlots-1].StationsLen > 0) {
			maxSlots++
		}
		for ii := 0; ii < maxSlots && ii < MAXASSIGNS; ii++ {
			assignCopy := dispatch.Assigns[ii]
			ok := assignCopy.AddShip(id, ori, des)
			if ok {
