population.algorithm:
Modified greedy insertion with cost-aware candidate evaluation and fallback expansion to empty assigns when all existing routes fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	availableIndices := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		availableIndices = append(availableIndices, i)
	}
	for orderIdx := range oris {
		bestCandidate := candidate{assignIdx: -1, costDelta: 1e100, ok: false}
		originalCosts := make([]float64, len(availableIndices))
		for idxPos, assignIdx := range availableIndices {
			originalCosts[idxPos] = dispatch.Assigns[assignIdx].Cost
			success := dispatch.Assigns[assignIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if success {
				dispatch.Assigns[assignIdx].GenRoute()
				if dispatch.Assigns[assignIdx].Cost >= 0 {
					delta := dispatch.Assigns[assignIdx].Cost - originalCosts[idxPos]
					if delta < bestCandidate.costDelta {
						bestCandidate.assignIdx = assignIdx
						bestCandidate.costDelta = delta
						bestCandidate.ok = true
					}
				}
			}
			dispatch.Assigns[assignIdx].RemoveShip(total_ship + orderIdx)
			dispatch.Assigns[assignIdx].Cost = originalCosts[idxPos]
			dispatch.Assigns[assignIdx].GenRoute()
		}
		inserted := false
		if bestCandidate.ok {
			finalSuccess := dispatch.Assigns[bestCandidate.assignIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if finalSuccess {
				dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
				if dispatch.Assigns[bestCandidate.assignIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestCandidate.assignIdx].RemoveShip(total_ship + orderIdx)
					dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
				}
			}
		}
		if !inserted {
			fallbackUsed := false
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				success := dispatch.Assigns[newIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
				if success {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
						dispatch.AssignsLen++
						availableIndices = append(availableIndices, newIdx)
						fallbackUsed = true
					} else {
						dispatch.Assigns[newIdx].RemoveShip(total_ship + orderIdx)
						dispatch.Assigns[newIdx].GenRoute()
					}
				}
			}
			if !fallbackUsed {
				for i := 0; i < dispatch.AssignsLen && !fallbackUsed; i++ {
					oldCost := dispatch.Assigns[i].Cost
					success := dispatch.Assigns[i].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
					if success {
						dispatch.Assigns[i].GenRoute()
						if dispatch.Assigns[i].Cost >= 0 {
							fallbackUsed = true
						} else {
							dispatch.Assigns[i].RemoveShip(total_ship + orderIdx)
							dispatch.Assigns[i].Cost = oldCost
							dispatch.Assigns[i].GenRoute()
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

