		originalCosts := make([]float64, len(availableIndices))
		for idxPos, assignIdx := range availableIndices {
			originalCosts[idxPos] = dispatch.Assigns[assignIdx].Cost
			success := dispatch.Assigns[assignIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if success {
				dispatch.Assigns[assignIdx].GenRoute()
				if dispatch.Assigns[assignIdx].Cost >= 0 {
					delta := dispatch.Assigns[assignIdx].Cost - originalCosts[idxPos]
					if delta < bestCandidate.costDelta {
						bestCandidate.assignIdx = assignIdx
						bestCandidate.costDelta = delta
						bestCandidate.ok = true
					}
				}
			}
			dispatch.Assigns[assignIdx].RemoveShip(total_ship + orderIdx)
			dispatch.Assigns[assignIdx].Cost = originalCosts[idxPos]
			dispatch.Assigns[assignIdx].GenRoute()
		}
		inserted := false
		if bestCandidate.ok {
			finalSuccess := dispatch.Assigns[bestCandidate.assignIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if finalSuccess {
				dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
				if dispatch.Assigns[bestCandidate.assignIdx].Cost >= 0 {
