					dispatch.Assigns[bestCandidate.assignIdx].RemoveShip(total_ship + orderIdx)
					dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
				}
			}
		}
		if !inserted {
			fallbackUsed := false
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				success := dispatch.Assigns[newIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
				if success {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
						dispatch.AssignsLen++
						availableIndices = append(availableIndices, newIdx)
						fallbackUsed = true
					} else {
						dispatch.Assigns[newIdx].RemoveShip(total_ship + orderIdx)
						dispatch.Assigns[newIdx].GenRoute()
					}
				}
			}
			if !fallbackUsed {
				for i := 0; i < dispatch.AssignsLen && !fallbackUsed; i++ {
					oldCost := dispatch.Assigns[i].Cost
					success := dispatch.Assigns[i].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
					if success {
						dispatch.Assigns[i].GenRoute()
						if dispatch.Assigns[i].Cost >= 0 {
							fallbackUsed = true
						} else {
							dispatch.Assigns[i].RemoveShip(total_ship + orderIdx)
							dispatch.Assigns[i].Cost = oldCost
							dispatch.Assigns[i].GenRoute()
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

