Greedy insertion with regret-based scoring evaluating multiple candidate positions per assign using time window feasibility and marginal distance increase, then fallback to empty assign creation if all attempts fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type Candidate struct {
		assignIdx  int
		pos        int
		score      float64
		cost       float64
		valid      bool
	}
	const REGRET_K = 3
	for jj := range oris {
		ori := oris[jj]
		des := dess[jj]
		bestCandidate := Candidate{valid: false}
		var bestEmptyIdx int = -1
		for ii := 0; ii < MAXASSIGNS; ii++ {
			if ii >= dispatch.AssignsLen || dispatch.Assigns[ii].StationsLen == 0 {
				if bestEmptyIdx == -1 && ii < MAXASSIGNS {
					bestEmptyIdx = ii
				}
				continue
			}
			tempAssign := dispatch.Assigns[ii]
			insertedId := total_ship + jj
			if tempAssign.AddShip(insertedId, ori, des) {
				tempAssign.GenRoute()
				if tempAssign.Cost >= 0 {
					marginalCost := tempAssign.Cost - dispatch.Assigns[ii].Cost
					candidatesForRegret := make([]float64, 0, 8)
					candidatesForRegret = append(candidatesForRegret, marginalCost)
					regretScore := 0.0
					kCount := 1
					for kk := 0; kk < MAXASSIGNS && kCount < REGRET_K; kk++ {
						if kk != ii && (kk < dispatch.AssignsLen && dispatch.Assigns[kk].StationsLen > 0) {
							altAssign := dispatch.Assigns[kk]
							if altAssign.AddShip(insertedId, ori, des) {
								altAssign.GenRoute()
								if altAssign.Cost >= 0 {
									altMarginal := altAssign.Cost - dispatch.Assigns[kk].Cost
									candidatesForRegret = append(candidatesForRegret, altMarginal)
									kCount++
								}
								altAssign.RemoveShip(insertedId)
								altAssign.GenRoute()
							}
						}
					}
					for len(candidatesForRegret) < REGRET_K {
						candidatesForRegret = append(candidatesForRegret, 1e9)
					}
					sorted := make([]float64, len(candidatesForRegret))
					copy(sorted, candidatesForRegret)
					for m := 0; m < len(sorted)-1; m++ {
						for n := m + 1; n < len(sorted); n++ {
							if sorted[m] > sorted[n] {
								sorted[m], sorted[n] = sorted[n], sorted[m]
							}
						}
					}
					if len(sorted) >= REGRET_K {
						regretScore = sorted[REGRET_K-1] - sorted[0]
					}
					timeFeasibilityScore := 0.0
					if ori.TimeEnd > 0 && des.TimeEnd > 0 {
						arrivalOri := cal_dis(tempAssign.StationCurrent, ori)
						arrivalDes := arrivalOri + cal_dis(ori, des)
						if arrivalOri <= float64(ori.TimeEnd) && arrivalDes <= float64(des.TimeEnd) {
							timeFeasibilityScore = 1000000.0 / (arrivalOri + arrivalDes + 1.0)
						}
					}
					finalScore := regretScore*10.0 - marginalCost + timeFeasibilityScore
					if !bestCandidate.valid || finalScore > bestCandidate.score {
						bestCandidate.assignIdx = ii
						bestCandidate.score = finalScore
						bestCandidate.cost = marginalCost
						bestCandidate.valid = true
					}
				}
				tempAssign.RemoveShip(insertedId)
				tempAssign.GenRoute()
			}
		}
		insertedId := total_ship + jj
		if bestCandidate.valid {
			dispatch.Assigns[bestCandidate.assignIdx].AddShip(insertedId, ori, des)
			dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
		} else {
			useIdx := bestEmptyIdx
			if useIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
				useIdx = dispatch.AssignsLen
				dispatch.AssignsLen++
			}
			if useIdx >= 0 && useIdx < MAXASSIGNS {
				ok := dispatch.Assigns[useIdx].AddShip(insertedId, ori, des)
				if ok {
					dispatch.Assigns[useIdx].GenRoute()
					if dispatch.Assigns[useIdx].Cost < 0 {
						dispatch.Assigns[useIdx].RemoveShip(insertedId)
						dispatch.Assigns[useIdx].GenRoute()
					} else {
						if useIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = useIdx + 1
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

