population.algorithm:
Use greedy cost minimization with fallback seed insertion: evaluate all feasible assigns per order using marginal cost increase weighted by distance and time window tightness, choose best if below threshold, else use minimal extra distance heuristic; if still unassigned, force insert into first empty assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type candidate struct {
		idx       int
		costDelta float64
		ok        bool
	}
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		bestCand := candidate{idx: -1, costDelta: 1e18, ok: false}
		fallbackEmptyIdx := -1
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen {
				if fallbackEmptyIdx == -1 {
					fallbackEmptyIdx = i
				}
				continue
			}
			assignCopy := dispatch.Assigns[i]
			oldCost := assignCopy.Cost
			if !assignCopy.AddShip(shipID, ori, des) {
				continue
			}
			assignCopy.GenRoute()
			newCost := assignCopy.Cost
			if newCost >= 0 {
				delta := newCost - oldCost
				timeTightWeight := 1.0
				if ori.TimeStart > 0 && ori.TimeEnd > ori.TimeStart {
					windowSize := float64(ori.TimeEnd - ori.TimeStart)
					if windowSize > 0 {
						baseDist := cal_dis(assignCopy.StationCurrent, ori)
						arriveTime := baseDist * 0.5
						timePressure := 0.0
						if arriveTime < float64(ori.TimeStart) {
							wait := float64(ori.TimeStart) - arriveTime
							timePressure = wait / windowSize
						} else if arriveTime > float64(ori.TimeEnd) {
							lateness := arriveTime - float64(ori.TimeEnd)
							timePressure = lateness*10.0 / windowSize
						}
						timeTightWeight = 1.0 + timePressure*0.3
					}
				}
				score := delta * timeTightWeight
				if score < bestCand.costDelta {
					bestCand.idx = i
					bestCand.costDelta = score
					bestCand.ok = true
				}
			}
			assignCopy.RemoveShip(shipID)
			assignCopy.GenRoute()
		}
		inserted := false
		if bestCand.ok {
			if !dispatch.Assigns[bestCand.idx].AddShip(shipID, ori, des) {
				bestCand.ok = false
			} else {
				dispatch.Assigns[bestCand.idx].GenRoute()
				inserted = true
			}
		}
		if !inserted && fallbackEmptyIdx >= 0 {
			if fallbackEmptyIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = fallbackEmptyIdx + 1
			}
			if dispatch.Assigns[fallbackEmptyIdx].AddShip(shipID, ori, des) {
				dispatch.Assigns[fallbackEmptyIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			minExtraIdx := -1
			minExtraDist := 1e18
			for i := 0; i < dispatch.AssignsLen; i++ {
				currentPos := dispatch.Assigns[i].StationCurrent
				pickDist := cal_dis(currentPos, ori)
				deliverDist := cal_dis(ori, des)
				extraDist := pickDist + deliverDist
				if extraDist < minExtraDist {
					minExtraDist = extraDist
					minExtraIdx = i
				}
			}
			if minExtraIdx >= 0 {
				if dispatch.Assigns[minExtraIdx].AddShip(shipID, ori, des) {
					dispatch.Assigns[minExtraIdx].GenRoute()
					inserted = true
				}
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				if dispatch.Assigns[newIdx].AddShip(shipID, ori, des) {
					dispatch.Assigns[newIdx].GenRoute()
					dispatch.AssignsLen++
					inserted = true
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

