Greedy best-fit insertion with time-window feasibility check, fallback to new empty assign if all existing routes reject the order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestDelta := math.Inf(1)

		// Try inserting into each existing non-empty assign
		for i := 0; i < dispatch.AssignsLen; i++ {
			assignCopy := dispatch.Assigns[i]
			success := assignCopy.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if success {
				assignCopy.GenRoute()
				if assignCopy.Cost >= 0 {
					delta := assignCopy.Cost - dispatch.Assigns[i].Cost
					if delta < bestDelta {
						bestDelta = delta
						bestAssignIdx = i
					}
				}
			}
		}

		// Also try inserting into the next empty assign slot (fallback/new vehicle)
		nextEmptyIdx := dispatch.AssignsLen
		if nextEmptyIdx < MAXASSIGNS {
			assignCopy := dispatch.Assigns[nextEmptyIdx]
			success := assignCopy.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if success {
				assignCopy.GenRoute()
				if assignCopy.Cost >= 0 {
					delta := assignCopy.Cost
					if delta < bestDelta {
						bestDelta = delta
						bestAssignIdx = nextEmptyIdx
					}
				}
			}
		}

		// Perform the actual insertion on the chosen assign
		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			actualSuccess := dispatch.Assigns[bestAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if actualSuccess {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

