Greedy insertion with route diversification using marginal cost per unit distance weighted by time window slack and load factor, plus randomization tie-breaking and forced seeding of new vehicles when beneficial.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestScore := math.Inf(1)

		ori := oris[shipIdx]
		des := dess[shipIdx]
		loadSum := ori.Load + des.Load

		timeSlackOri := ori.TimeEnd - ori.TimeStart
		if timeSlackOri <= 0 {
			timeSlackOri = 1
		}
		timeSlackDes := des.TimeEnd - des.TimeStart
		if timeSlackDes <= 0 {
			timeSlackDes = 1
		}
		slackWeight := float64(timeSlackOri*timeSlackDes) / 10000.0
		if slackWeight < 0.5 {
			slackWeight = 0.5
		} else if slackWeight > 2.0 {
			slackWeight = 2.0
		}

		for i := 0; i < dispatch.AssignsLen; i++ {
			assignCopy := dispatch.Assigns[i]
			oldCost := assignCopy.Cost
			success := assignCopy.AddShip(total_ship+shipIdx, ori, des)
			if success {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				if newCost >= 0 {
					marginalCost := newCost - oldCost
					distanceFactor := cal_dis(assignCopy.StationCurrent, ori) + cal_dis(ori, des)
					if distanceFactor <= 0 {
						distanceFactor = 1.0
					}
					score := (marginalCost / distanceFactor) * slackWeight / (float64(loadSum)/10.0 + 1.0)

					tieBreak := 0.0
					if score == bestScore {
						tieBreak = float64(i%3) * 0.001
					}
					score += tieBreak

					if score < bestScore {
						bestScore = score
						bestAssignIdx = i
					}
				}
			}
		}

		nextEmptyIdx := dispatch.AssignsLen
		if nextEmptyIdx < MAXASSIGNS {
			assignCopy := dispatch.Assigns[nextEmptyIdx]
			success := assignCopy.AddShip(total_ship+shipIdx, ori, des)
			if success {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				if newCost >= 0 {
					baseDistance := cal_dis(Station{}, ori) + cal_dis(ori, des)
					if baseDistance <= 0 {
						baseDistance = 1.0
					}
					score := (newCost / baseDistance) * slackWeight * 0.8 / (float64(loadSum)/10.0 + 1.0)

					if score < bestScore || bestAssignIdx == -1 {
						bestScore = score
						bestAssignIdx = nextEmptyIdx
					}
				}
			}
		}

		fallbackSeedIdx := -1
		if bestAssignIdx == -1 {
			for j := dispatch.AssignsLen; j < MAXASSIGNS; j++ {
				testAssign := dispatch.Assigns[j]
				ok := testAssign.AddShip(total_ship+shipIdx, ori, des)
				if ok {
					testAssign.GenRoute()
					if testAssign.Cost >= 0 {
						fallbackSeedIdx = j
						break
					}
				}
			}
			if fallbackSeedIdx != -1 {
				bestAssignIdx = fallbackSeedIdx
			}
		}

		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			actualSuccess := dispatch.Assigns[bestAssignIdx].AddShip(total_ship+shipIdx, ori, des)
			if actualSuccess {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

