func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    const REGRET_K = 3
    n_orders := len(oris)
    n_routes := dispatch.AssignsLen
    for jj := 0; jj < n_orders; jj++ {
        best_assign_idx := -1
        best_cost_inc := 1e18
        best_second_cost := 1e18
        ship_id := total_ship + jj
        origin := oris[jj]
        dest := dess[jj]
        for ri := 0; ri <= n_routes; ri++ {
            var cur_assign Assign
            if ri < n_routes {
                cur_assign = dispatch.Assigns[ri]
            } else {
                cur_assign = Assign{}
            }
            saved_cost := cur_assign.Cost
            ok := false
            if ri < n_routes {
                ok = dispatch.Assigns[ri].AddShip(ship_id, origin, dest)
            } else {
                tmp := &dispatch.Assigns[n_routes]
                ok = tmp.AddShip(ship_id, origin, dest)
                if ok {
                    dispatch.Assigns[n_routes].GenRoute()
                }
            }
            if ok {
                new_cost := dispatch.Assigns[ri].Cost
                if ri == n_routes {
                    new_cost = dispatch.Assigns[n_routes].Cost
                }
                cost_inc := new_cost - saved_cost
                if cost_inc < best_cost_inc || (cost_inc == best_cost_inc && best_second_cost > 0) {
                    best_second_cost = best_cost_inc
                    best_cost_inc = cost_inc
                    best_assign_idx = ri
