func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	used := make([]bool, len(oris))
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestCostIncrease := 1e100
		currentShipID := total_ship + shipIdx
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assignCopy := dispatch.Assigns[ai]
			ok := assignCopy.AddShip(currentShipID, oris[shipIdx], dess[shipIdx])
			if ok {
				assignCopy.GenRoute()
				if assignCopy.Cost >= 0 {
					costInc := assignCopy.Cost - dispatch.Assigns[ai].Cost
					if costInc < bestCostIncrease {
						bestCostIncrease = costInc
						bestAssignIdx = ai
					}
				}
			}
		}
		if bestAssignIdx >= 0 {
			dispatch.Assigns[bestAssignIdx].AddShip(currentShipID, oris[shipIdx], dess[shipIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
			used[shipIdx] = true
		}
	}
	for shipIdx := range oris {
		if used[shipIdx] {
			continue
		}
		currentShipID := total_ship + shipIdx
		inserted := false
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			if dispatch.Assigns[ai].AddShip(currentShipID, oris[shipIdx], dess[shipIdx]) {
				dispatch.Assigns[ai].GenRoute()
				if dispatch.Assigns[ai].Cost >= 0 {
					inserted = true
					break
				} else {
					dispatch.Assigns[ai].RemoveShip(currentShipID)
					dispatch.Assigns[ai].GenRoute()
				}
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				newAi := dispatch.AssignsLen
				dispatch.Assigns[newAi].AddShip(currentShipID, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[newAi].GenRoute()
				if dispatch.Assigns[newAi].Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					dispatch.Assigns[newAi].RemoveShip(currentShipID)
					dispatch.Assigns[newAi].GenRoute()
				}
			}
		}
		if !inserted {
			fallbackCreated := false
			for ai := dispatch.AssignsLen; ai < MAXASSIGNS; ai++ {
				if dispatch.Assigns[ai].AddShip(currentShipID, oris[shipIdx], dess[shipIdx]) {
					dispatch.Assigns[ai].GenRoute()
					if dispatch.Assigns[ai].Cost >= 0 {
						dispatch.AssignsLen = ai + 1
						fallbackCreated = true
						break
					} else {
						dispatch.Assigns[ai].RemoveShip(currentShipID)
						dispatch.Assigns[ai].GenRoute()
					}
				}
			}
			if !fallbackCreated && dispatch.AssignsLen < MAXASSIGNS {
				emptyAi := dispatch.AssignsLen
				dispatch.Assigns[emptyAi] = Assign{}
				if dispatch.Assigns[emptyAi].AddShip(currentShipID, oris[shipIdx], dess[shipIdx]) {
