Greedy insertion with best-fit selection using time-window slack and distance increase as scoring metrics, processing all orders sequentially while falling back to empty vehicle creation when no existing route can accommodate an order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for j := 0; j < orderCount; j++ {
		bestIdx := -1
		bestScore := math.MaxFloat64
		shipID := total_ship + j
		ori := oris[j]
		des := dess[j]
		for i := 0; i < dispatch.AssignsLen; i++ {
			assignCopy := dispatch.Assigns[i]
			ok := assignCopy.AddShip(shipID, ori, des)
			if ok {
				assignCopy.GenRoute()
				cost := assignCopy.Cost
				if cost >= 0 {
					increase := cost - dispatch.Assigns[i].Cost
					timeSlackPenalty := 0.0
					stations := assignCopy.Stations[:assignCopy.StationsLen]
					for k := 1; k < len(stations); k++ {
						prev := stations[k-1]
						curr := stations[k]
						travelTime := cal_dis(prev, curr)
						waitTime := 0.0
						if travelTime < float64(curr.TimeStart-prev.TimeEnd) {
							waitTime = float64(curr.TimeStart-prev.TimeEnd) - travelTime
						}
						slack := float64(curr.TimeEnd-curr.TimeStart) - waitTime
						if slack < 0 {
							timeSlackPenalty -= slack * 10.0
						} else if slack < 30 {
							timeSlackPenalty += (30.0 - slack) * 0.5
						}
					}
					score := increase*0.8 + timeSlackPenalty*0.2
					if score < bestScore {
						bestScore = score
						bestIdx = i
					}
				}
			}
		}
		fallbackIdx := dispatch.AssignsLen
		if fallbackIdx >= MAXASSIGNS {
			fallbackIdx = -1
		}
		inserted := false
		if bestIdx >= 0 {
			actualOk := dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			if actualOk {
				dispatch.Assigns[bestIdx].GenRoute()
				if dispatch.Assigns[bestIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestIdx].RemoveShip(shipID)
					dispatch.Assigns[bestIdx].GenRoute()
				}
			}
		}
		if !inserted && fallbackIdx >= 0 {
			actualOk := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
			if actualOk {
				dispatch.Assigns[fallbackIdx].GenRoute()
				if dispatch.Assigns[fallbackIdx].Cost >= 0 {
					dispatch.AssignsLen = fallbackIdx + 1
					inserted = true
				} else {
					dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
					dispatch.Assigns[fallbackIdx].GenRoute()
				}
			}
		}
		if !inserted && fallbackIdx < 0 {
			tempIdx := 0
			foundFallback := false
			for tempIdx < dispatch.AssignsLen {
				dummy := dispatch.Assigns[tempIdx]
				ok := dummy.AddShip(shipID, ori, des)
				if ok {
					dummy.GenRoute()
					if dummy.Cost >= 0 {
						foundFallback = true
						break
					}
				}
				tempIdx++
			}
			if foundFallback {
				dispatch.Assigns[tempIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[tempIdx].GenRoute()
				inserted = true
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

