Greedy insertion with regret-based heuristic: evaluate multiple candidate assigns per ship using marginal cost increase, prioritize ships with largest cost difference between best and second-best options, fallback to first feasible assign if no improvement.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	used := make([]bool, len(oris))
	candidateAssigns := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		candidateAssigns = append(candidateAssigns, i)
	}
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestDelta := 1e18
		secondBestDelta := 1e18
		originalCosts := make([]float64, len(candidateAssigns))
		feasibleAssigns := make([]int, 0, len(candidateAssigns))
		deltaCosts := make([]float64, 0, len(candidateAssigns))
		for _, idx := range candidateAssigns {
			originalCosts[idx] = dispatch.Assigns[idx].Cost
			ok := dispatch.Assigns[idx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					feasibleAssigns = append(feasibleAssigns, idx)
					delta := dispatch.Assigns[idx].Cost - originalCosts[idx]
					deltaCosts = append(deltaCosts, delta)
					if delta < bestDelta {
						secondBestDelta = bestDelta
						bestDelta = delta
						bestAssignIdx = idx
					} else if delta < secondBestDelta {
						secondBestDelta = delta
					}
				}
				dispatch.Assigns[idx].RemoveShip(total_ship + shipIdx)
				dispatch.Assigns[idx].GenRoute()
				dispatch.Assigns[idx].Cost = originalCosts[idx]
			}
		}
		selectedIdx := -1
		if bestAssignIdx >= 0 {
			if secondBestDelta < 1e17 {
				regret := secondBestDelta - bestDelta
				maxRegretIdx := bestAssignIdx
				maxRegretVal := regret
				for i, idx := range feasibleAssigns {
					localBest := bestDelta
					localSecond := secondBestDelta
					if idx == bestAssignIdx {
						continue
					}
					curDelta := deltaCosts[i]
					if curDelta < localBest {
						localSecond = localBest
						localBest = curDelta
					} else if curDelta < localSecond {
						localSecond = curDelta
					}
					reg := localSecond - localBest
					if reg > maxRegretVal {
						maxRegretVal = reg
						maxRegretIdx = idx
					}
				}
				if maxRegretVal > regret*0.5 && len(feasibleAssigns) > 1 {
					selectedIdx = maxRegretIdx
				} else {
					selectedIdx = bestAssignIdx
				}
			} else {
				selectedIdx = bestAssignIdx
			}
		}
		if selectedIdx < 0 {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				dispatch.Assigns[newIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
					selectedIdx = newIdx
				}
			}
		}
		if selectedIdx >= 0 {
			dispatch.Assigns[selectedIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			dispatch.Assigns[selectedIdx].GenRoute()
			used[shipIdx] = true
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

