Regret-based greedy insertion with time-window slack prioritization and multiple candidate fallback: compute regret value as difference between two best insertion costs per assign, prioritize orders with high regret, use weighted score combining marginal cost increase, time-window tightness penalty, and distance efficiency gain, then attempt safe seed insertion into new assign if no feasible insertion found.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	if nOrders == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type OrderInfo struct {
		idx        int
		bestCosts  [2]float64
		bestAssign [2]int
		regret     float64
		isUsed     bool
	}
	orderInfos := make([]OrderInfo, nOrders)

	for i := 0; i < nOrders; i++ {
		orderInfos[i].idx = i
		orderInfos[i].bestCosts = [2]float64{1e100, 1e100}
		orderInfos[i].bestAssign = [2]int{-1, -1}
		orderInfos[i].regret = 0
		orderInfos[i].isUsed = false
	}

	for iter := 0; iter < nOrders; iter++ {
		maxRegretVal := -1e100
		selectedOrderIdx := -1
		for oi := 0; oi < nOrders; oi++ {
			if orderInfos[oi].isUsed {
				continue
			}
			if iter == 0 || (orderInfos[oi].bestAssign[0] < 0 && orderInfos[oi].bestAssign[1] < 0) {
				currentShipID := total_ship + oi
				firstBest := 1e100
				secondBest := 1e100
				bestA1 := -1
				bestA2 := -1
				for ai := 0; ai < dispatch.AssignsLen; ai++ {
					oldCost := dispatch.Assigns[ai].Cost
					testAssign := dispatch.Assigns[ai]
					ok := testAssign.AddShip(currentShipID, oris[oi], dess[oi])
					if ok {
						testAssign.GenRoute()
						if testAssign.Cost >= 0 {
							inc := testAssign.Cost - oldCost
							if inc < firstBest {
								secondBest = firstBest
								bestA2 = bestA1
								firstBest = inc
								bestA1 = ai
							} else if inc < secondBest {
								secondBest = inc
								bestA2 = ai
							}
						}
					}
				}
				orderInfos[oi].bestCosts[0] = firstBest
				orderInfos[oi].bestCosts[1] = secondBest
				orderInfos[oi].bestAssign[0] = bestA1
				orderInfos[oi].bestAssign[1] = bestA2
			}
			regretVal := 0.0
			if orderInfos[oi].bestAssign[0] >= 0 && orderInfos[oi].bestAssign[1] >= 0 {
				regretVal = orderInfos[oi].bestCosts[1] - orderInfos[oi].bestCosts[0]
			} else if orderInfos[oi].bestAssign[0] >= 0 {
				regretVal = 2.5*orderInfos[oi].bestCosts[0] + 50.0
			}
			timeWindowTightness := 0.0
			if oris[oi].TimeEnd > oris[oi].TimeStart {
				timeWindowTightness = 500.0 / float64(oris[oi].TimeEnd-oris[oi].TimeStart+1)
			}
			score := regretVal + timeWindowTightness
			if score > maxRegretVal {
				maxRegretVal = score
				selectedOrderIdx = oi
			}
		}

		if selectedOrderIdx < 0 {
			break
		}
		oi := selectedOrderIdx
		orderInfos[oi].isUsed = true
		currentShipID := total_ship + oi
		inserted := false

		if orderInfos[oi].bestAssign[0] >= 0 {
			bestAi := orderInfos[oi].bestAssign[0]
			testAssign := dispatch.Assigns[bestAi]
			ok := testAssign.AddShip(currentShipID, oris[oi], dess[oi])
			if ok {
				testAssign.GenRoute()
				if testAssign.Cost >= 0 {
					dispatch.Assigns[bestAi].AddShip(currentShipID, oris[oi], dess[oi])
					dispatch.Assigns[bestAi].GenRoute()
					inserted = true
				}
			}
		}

		if !inserted {
			for ai := 0; ai < dispatch.AssignsLen; ai++ {
				testAssign := dispatch.Assigns[ai]
				ok := testAssign.AddShip(currentShipID, oris[oi], dess[oi])
				if ok {
					testAssign.GenRoute()
					if testAssign.Cost >= 0 {
						dispatch.Assigns[ai].AddShip(currentShipID, oris[oi], dess[oi])
						dispatch.Assigns[ai].GenRoute()
						inserted = true
						break
					}
				}
			}
		}

		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				newAi := dispatch.AssignsLen
				testAssign := dispatch.Assigns[newAi]
				ok := testAssign.AddShip(currentShipID, oris[oi], dess[oi])
				if ok {
					testAssign.GenRoute()
					if testAssign.Cost >= 0 {
						dispatch.Assigns[newAi].AddShip(currentShipID, oris[oi], dess[oi])
						dispatch.Assigns[newAi].GenRoute()
						dispatch.AssignsLen++
						inserted = true
					}
				}
			}
		}

		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			for ai := dispatch.AssignsLen; ai < MAXASSIGNS; ai++ {
				testAssign := dispatch.Assigns[ai]
				ok := testAssign.AddShip(currentShipID, oris[oi], dess[oi])
				if ok {
					testAssign.GenRoute()
					if testAssign.Cost >= 0 {
