				if testAssign.Cost >= 0 {
					dispatch.Assigns[emptyAi].AddShip(currentShipID, oris[oi], dess[oi])
					dispatch.Assigns[emptyAi].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}

	for oi := 0; oi < nOrders; oi++ {
