func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		deltaCost float64
		feasible  bool
	}
	totalOrders := len(oris)
	for oidx := 0; oidx < totalOrders; oidx++ {
		candidates := make([]candidate, 0, MAXASSIGNS*2)
		ori := oris[oidx]
		des := dess[oidx]
		shipID := total_ship + oidx
		baseCost := dispatch.TotalCost
		bestCandidateIdx := -1
		bestDelta := 1e18
		foundFeasible := false

		// First pass: evaluate existing non‑empty assigns
		for aidx := 0; aidx < dispatch.AssignsLen; aidx++ {
			oldCost := dispatch.Assigns[aidx].Cost
			ok := dispatch.Assigns[aidx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[aidx].GenRoute()
				newCost := dispatch.Assigns[aidx].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					candidates = append(candidates, candidate{assignIdx: aidx, deltaCost: delta, feasible: true})
					if delta < bestDelta {
						bestDelta = delta
						bestCandidateIdx = len(candidates) - 1
						foundFeasible = true
					}
				}
				dispatch.Assigns[aidx].RemoveShip(shipID)
				dispatch.Assigns[aidx].GenRoute()
			}
		}
		// Second pass: evaluate empty/new assigns (existing empty ones first, then create new slot if needed)
		startNew := dispatch.AssignsLen
		endNew := startNew + 1
		if endNew > MAXASSIGNS {
			endNew = MAXASSIGNS
		}
		for aidx := startNew; aidx < endNew; aidx++ {
			ok := dispatch.Assigns[aidx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[aidx].GenRoute()
				newCost := dispatch.Assigns[aidx].Cost
				if newCost >= 0 {
					delta := newCost
					candidates = append(candidates, candidate{assignIdx: aidx, deltaCost: delta, feasible: true})
					if delta < bestDelta {
						bestDelta = delta
						bestCandidateIdx = len(candidates) - 1
						foundFeasible = true
					}
				}
				dispatch.Assigns[aidx].RemoveShip(shipID)
				dispatch.Assigns[aidx].GenRoute()
			}
		}

		if foundFeasible {
			chosen := candidates[bestCandidateIdx]
			actualOk := dispatch.Assigns[chosen.assignIdx].AddShip(shipID, ori, des)
			if actualOk {
				dispatch.Assigns[chosen.assignIdx].GenRoute()
				if chosen.assignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = chosen.assignIdx + 1
				}
			}
		} else {
			// Fallback: safe seed‑style insertion – try every assign slot until one works
			inserted := false
			for tryIdx := 0; tryIdx <= dispatch.AssignsLen && tryIdx < MAXASSIGNS; tryIdx++ {
				ok := dispatch.Assigns[tryIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[tryIdx].GenRoute()
